import{_ as i,o as e,c as a,a2 as o}from"./chunks/framework.VshInwhI.js";const m=JSON.parse('{"title":"后端开发流程","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/10-dev-flow.md","filePath":"mango-pmo/rules/backend/10-dev-flow.md"}'),r={name:"mango-pmo/rules/backend/10-dev-flow.md"};function t(d,l,c,n,h,u){return e(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="后端开发流程" tabindex="-1">后端开发流程 <a class="header-anchor" href="#后端开发流程" aria-label="Permalink to &quot;后端开发流程&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><ul><li>本文件只约束后端开发。</li><li>通用流程以 <a href="./../00-dev-flow">00-dev-flow.md</a> 为准。</li></ul><h2 id="_2-开发前" tabindex="-1">2. 开发前 <a class="header-anchor" href="#_2-开发前" aria-label="Permalink to &quot;2. 开发前&quot;">​</a></h2><p>必须明确：</p><ul><li>目标</li><li>范围</li><li>验收标准</li><li>影响模块</li><li>接口变化</li><li>数据变化</li><li>测试范围</li></ul><p>必须先拆解需求并提取：</p><ul><li>业务对象：聚合根、实体、值对象、关联对象和跨模块引用。</li><li>字典和枚举：状态、类型、来源、级别、动作、开关等有限选项。</li><li>数据模型：表、字段、索引、唯一约束、审计字段、租户字段和历史数据影响。</li><li>接口模型：Command、Query、VO、分页结果、批量操作入参和错误返回。</li><li>业务规则：状态流转、权限边界、数据权限、幂等、并发、校验和异常分支。</li><li>辅助数据：组织、用户、角色、租户、部门、分类、标签、上级对象等依赖数据。</li><li>设计模式：策略、模板方法、工厂、状态机、规格校验、事件发布等是否有真实复用价值。</li><li>复用能力：已有 API、service、provider、checker、validator、converter、mapper 和测试物料。</li></ul><p>拆解结果必须决定：</p><ul><li>哪些模型进入 <code>api</code> 契约，哪些模型只留在 <code>core</code>。</li><li>哪些能力放在当前模块，哪些能力通过其它模块 API 调用。</li><li>哪些字典和枚举需要后端统一定义，哪些只属于页面筛选条件。</li><li>哪些设计模式能降低复杂度，哪些只是无意义包装。</li><li>哪些规则需要测试覆盖，哪些规则需要集成验证。</li></ul><h2 id="_3-开发中" tabindex="-1">3. 开发中 <a class="header-anchor" href="#_3-开发中" aria-label="Permalink to &quot;3. 开发中&quot;">​</a></h2><ul><li>只改本次需求相关代码。</li><li>新增代码必须遵守最新规范。</li><li>不把 <code>PO</code>、<code>Entity</code> 直接暴露到 API。</li><li>不新增跨模块错误依赖。</li><li>不在本次任务中顺手扩大改动范围。</li></ul><h2 id="_4-数据库变更" tabindex="-1">4. 数据库变更 <a class="header-anchor" href="#_4-数据库变更" aria-label="Permalink to &quot;4. 数据库变更&quot;">​</a></h2><ul><li>DDL 变更必须使用 Flyway migration。</li><li>禁止直接改线上库。</li><li>每次变更新增 migration 文件。</li><li>不修改已执行的历史 migration。</li><li>migration 路径使用 <code>db/migration/{module}/V{version}__{description}.sql</code>。</li><li>migration 按模块隔离。</li></ul><h2 id="_5-提交前验证" tabindex="-1">5. 提交前验证 <a class="header-anchor" href="#_5-提交前验证" aria-label="Permalink to &quot;5. 提交前验证&quot;">​</a></h2><p>至少执行与改动范围对应的检查：</p><ul><li><code>mvn test</code></li><li><code>mvn verify</code></li><li><code>mvn pmd:check</code></li><li><code>mvn checkstyle:check</code></li><li><code>mvn mango:check</code></li></ul><h2 id="_6-提交要求" tabindex="-1">6. 提交要求 <a class="header-anchor" href="#_6-提交要求" aria-label="Permalink to &quot;6. 提交要求&quot;">​</a></h2><p>提交说明必须写清：</p><ul><li>改动范围</li><li>验证结果</li><li>未完成项</li><li>风险</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>没有设计就直接改跨模块边界</li><li>没有完成需求拆解就直接建表、写接口或写 service</li><li>没有验证就提交</li><li>直接修改生产数据结构</li><li>用一次性脚本替代正式 migration</li></ul>',22)])])}const _=i(r,[["render",t]]);export{m as __pageData,_ as default};
